-- ═══ Philemon Chapter 1 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Philemon', 1, 'kids', 1, 'Who wrote the letter to Philemon?', 'Paul', 'Peter', 'John', 'James', 'a', 'Philemon 1:1 — "Paul, a prisoner of Jesus Christ, and Timothy our brother, unto Philemon."'),
('Philemon', 1, 'kids', 2, 'What was the name of the runaway servant Paul was sending back?', 'Onesimus', 'Timothy', 'Titus', 'Barnabas', 'a', 'Philemon 1:10 — "I beseech thee for my son Onesimus, whom I have begotten in my bonds."'),
('Philemon', 1, 'kids', 3, 'What did Paul ask Philemon to do with Onesimus?', 'Receive him back as a beloved brother', 'Punish him severely', 'Sell him to someone else', 'Send him to Rome', 'a', 'Philemon 1:16 — "receive him… Not now as a servant, but above a servant, a brother beloved."'),
-- Teens
('Philemon', 1, 'teens', 1, 'Where was Paul when he wrote the letter to Philemon?', 'In prison (in bonds)', 'At the temple in Jerusalem', 'On a ship at sea', 'In Philemon''s house', 'a', 'Philemon 1:1,9 — "Paul, a prisoner of Jesus Christ" and "being such an one as Paul the aged, and now also a prisoner of Jesus Christ."'),
('Philemon', 1, 'teens', 2, 'How does Paul describe Onesimus before and after his conversion?', 'Once unprofitable but now profitable to both Paul and Philemon', 'Always a faithful servant', 'A skilled craftsman who lost his way', 'A wealthy man who became poor', 'a', 'Philemon 1:11 — "Which in time past was to thee unprofitable, but now profitable to thee and to me."'),
('Philemon', 1, 'teens', 3, 'Rather than commanding Philemon, what approach does Paul take?', 'He appeals to him on the basis of love', 'He threatens church discipline', 'He sends a formal decree', 'He asks the other apostles to intervene', 'a', 'Philemon 1:8-9 — "though I might be much bold in Christ to enjoin thee… Yet for love''s sake I rather beseech thee."'),
('Philemon', 1, 'teens', 4, 'What does Paul offer to do regarding any debt Onesimus owes?', 'Paul says "put that on mine account" — he will repay it', 'He asks the church to take up a collection', 'He says the debt should be forgiven without payment', 'He says Onesimus should work it off', 'a', 'Philemon 1:18 — "If he hath wronged thee, or oweth thee ought, put that on mine account."'),
('Philemon', 1, 'teens', 5, 'What does Paul say Philemon''s love and faith have done?', 'Refreshed the hearts (bowels) of the saints', 'Built three new churches', 'Converted the whole city', 'Provided funding for Paul''s missions', 'a', 'Philemon 1:7 — "we have great joy and consolation in thy love, because the bowels of the saints are refreshed by thee, brother."'),
-- Adults
('Philemon', 1, 'adults', 1, 'What does Paul call Philemon in his greeting?', '"Our dearly beloved, and fellowlabourer"', '"A servant of the church"', '"The bishop of Colossae"', '"A teacher of the law"', 'a', 'Philemon 1:1 — "unto Philemon our dearly beloved, and fellowlabourer."'),
('Philemon', 1, 'adults', 2, 'Who else is addressed in the salutation besides Philemon?', 'Apphia (beloved), Archippus (fellowsoldier), and the church in Philemon''s house', 'Only Timothy and Titus', 'The entire church of Colossae by name', 'The Roman governor of the province', 'a', 'Philemon 1:2 — "And to our beloved Apphia, and Archippus our fellowsoldier, and to the church in thy house."'),
('Philemon', 1, 'adults', 3, 'What does Paul pray regarding Philemon''s faith?', '"That the communication of thy faith may become effectual by the acknowledging of every good thing which is in you in Christ Jesus"', '"That thy faith fail not in times of trouble"', '"That thy faith may move mountains"', '"That thy faith may convert the emperor"', 'a', 'Philemon 1:6 — "That the communication of thy faith may become effectual by the acknowledging of every good thing which is in you in Christ Jesus."'),
('Philemon', 1, 'adults', 4, 'What is the meaning of the name "Onesimus" and how does Paul play on it?', 'It means "useful/profitable" — Paul says he was once unprofitable but is now profitable, a wordplay on his name', 'It means "faithful" — Paul says he proved his name true', 'It means "servant" — Paul says he should be freed from that identity', 'It means "blessed" — Paul says he has been a blessing', 'a', 'Philemon 1:10-11 — Onesimus means "useful"; Paul writes "in time past was to thee unprofitable, but now profitable."'),
('Philemon', 1, 'adults', 5, 'What subtle reminder does Paul give Philemon in verse 19?', '"I Paul have written it with mine own hand, I will repay it: albeit I do not say to thee how thou owest unto me even thine own self besides"', '"Remember that I am an apostle with authority over you"', '"Remember the day I healed your mother"', '"Remember that the Lord watches all transactions"', 'a', 'Philemon 1:19 — Paul reminds Philemon that he owes Paul his very salvation — a gentle but powerful persuasion.'),
('Philemon', 1, 'adults', 6, 'What does Paul suggest may have been the providential reason for Onesimus''s departure?', '"Perhaps he therefore departed for a season, that thou shouldest receive him for ever" — temporary separation for eternal gain', 'God sent him away as punishment', 'Onesimus needed to learn a trade in Rome', 'Philemon needed to learn independence', 'a', 'Philemon 1:15 — "For perhaps he therefore departed for a season, that thou shouldest receive him for ever."'),
('Philemon', 1, 'adults', 7, 'What confidence does Paul express about Philemon''s response?', '"Having confidence in thy obedience I wrote unto thee, knowing that thou wilt also do more than I say"', '"I know you will do the minimum required"', '"I expect you to follow my direct command"', '"I am uncertain whether you will obey"', 'a', 'Philemon 1:21 — "Having confidence in thy obedience I wrote unto thee, knowing that thou wilt also do more than I say."'),
('Philemon', 1, 'adults', 8, 'What practical request does Paul make at the end of the letter?', 'Prepare a lodging for him, as he hopes to be granted to them through their prayers', 'Send money for his legal defense', 'Come visit him in prison', 'Send Onesimus back to Rome permanently', 'a', 'Philemon 1:22 — "But withal prepare me also a lodging: for I trust that through your prayers I shall be given unto you."');
